import type { ConsumeMessage } from "amqplib";

export type Handler<T> = (msg: T, raw: ConsumeMessage) => Promise<void> | void;

export interface EventMeta {
  type: string;
  exchange: string;
  routingKey: string;
}

/**
 * Decodes a raw message body into the typed shape. Default is
 * JSON.parse + utf8. Override to plug in a validator (zod/typia/ajv) —
 * runtime is otherwise unverified and the cast is taken on trust.
 */
export type ParseFn = (buf: Buffer) => unknown;

const defaultParse: ParseFn = (buf) => JSON.parse(buf.toString("utf8"));

export interface RegistryOptions {
  parse?: ParseFn;
}

export class Registry<
  // biome-ignore lint/suspicious/noExplicitAny: caller's spec defines its shape
  EM extends Record<string, any>,
  Registered extends keyof EM = never,
> {
  private handlers = new Map<keyof EM, Handler<unknown>>();
  private metaByType = new Map<keyof EM, EventMeta>();
  private parse: ParseFn;

  constructor(
    events: Readonly<Record<string, EventMeta>>,
    opts: RegistryOptions = {},
  ) {
    for (const meta of Object.values(events)) {
      this.metaByType.set(meta.type as keyof EM, meta);
    }
    this.parse = opts.parse ?? defaultParse;
  }

  on<K extends keyof EM>(
    type: K,
    handler: Handler<EM[K]>,
  ): Registry<EM, Registered | K> {
    if (this.handlers.has(type)) {
      console.warn(
        `Registry.on: handler for "${String(type)}" was already registered, overwriting`,
      );
    }
    this.handlers.set(type, handler as Handler<unknown>);
    return this as Registry<EM, Registered | K>;
  }

  dispatch = (raw: ConsumeMessage | null): void => {
    if (!raw) return;

    let msg: EM[keyof EM];
    try {
      msg = this.parse(raw.content) as EM[keyof EM];
    } catch (err) {
      console.error("Registry.dispatch: failed to parse message body", err);
      return;
    }

    const incoming = raw.fields.routingKey;

    // Fast path: producer publishes with the concrete event type as the
    // routing key, so most messages match an exact key in `handlers`.
    const direct = this.handlers.get(incoming as keyof EM);
    if (direct) {
      this.runHandler(direct, msg, raw, incoming);
      return;
    }

    // Slow path: incoming key didn't match a registered type literally,
    // so walk patterns for a wildcard match (`*`, `#`).
    for (const [type, handler] of this.handlers) {
      const meta = this.metaByType.get(type);
      if (!meta) continue;
      if (matchRoutingKey(meta.routingKey, incoming)) {
        this.runHandler(handler, msg, raw, String(type));
        return;
      }
    }
  };

  private runHandler(
    handler: Handler<unknown>,
    msg: unknown,
    raw: ConsumeMessage,
    label: string,
  ): void {
    try {
      const result = handler(msg, raw);
      if (result instanceof Promise) {
        result.catch((err: unknown) => {
          console.error(`Registry.dispatch: handler for "${label}" threw`, err);
        });
      }
    } catch (err) {
      console.error(`Registry.dispatch: handler for "${label}" threw`, err);
    }
  }

  toCallback<K extends Registered>(
    type: K,
  ): (raw: ConsumeMessage | null) => void {
    const handler = this.handlers.get(type);
    if (!handler) {
      throw new Error(
        `Registry.toCallback: no handler registered for "${String(type)}"`,
      );
    }
    return (raw) => {
      if (!raw) return;
      let msg: EM[K];
      try {
        msg = this.parse(raw.content) as EM[K];
      } catch (err) {
        console.error(
          `Registry.toCallback("${String(type)}"): failed to parse message body`,
          err,
        );
        return;
      }
      this.runHandler(handler, msg as unknown, raw, String(type));
    };
  }

  get bindings(): ReadonlyArray<{
    type: Registered;
    exchange: string;
    routingKey: string;
  }> {
    const out: Array<{
      type: Registered;
      exchange: string;
      routingKey: string;
    }> = [];
    for (const type of this.handlers.keys()) {
      const meta = this.metaByType.get(type);
      if (!meta) continue;
      out.push({
        type: type as Registered,
        exchange: meta.exchange,
        routingKey: meta.routingKey,
      });
    }
    return out;
  }
}

export function createRegistry<
  // biome-ignore lint/suspicious/noExplicitAny: caller's spec defines its shape
  EM extends Record<string, any>,
>(
  events: Readonly<Record<string, EventMeta>>,
  opts: RegistryOptions = {},
): Registry<EM> {
  return new Registry<EM>(events, opts);
}

/** RabbitMQ topic-exchange routing-key matcher: `*` = one word, `#` = zero or more. */
function matchRoutingKey(pattern: string, key: string): boolean {
  return matchSegments(pattern.split("."), key.split("."));
}

function matchSegments(
  p: ReadonlyArray<string>,
  k: ReadonlyArray<string>,
): boolean {
  if (p.length === 0) return k.length === 0;
  const head = p[0];
  const tail = p.slice(1);
  if (head === "#") {
    for (let i = 0; i <= k.length; i++) {
      if (matchSegments(tail, k.slice(i))) return true;
    }
    return false;
  }
  if (k.length === 0) return false;
  if (head === "*" || head === k[0]) return matchSegments(tail, k.slice(1));
  return false;
}
